import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import API from "../services/api";
import { useAuth } from "../context/AuthContext";
import "./Auth.css";

const STEPS = [
  {
    emoji: "👋",
    title: "Welcome to ChatApp!",
    desc: "A private messaging app built for real connections. Here's what makes it special:",
    points: [
      "🔒 You control who can message you",
      "📸 Share photos, videos & status stories",
      "✓✓ Blue ticks when messages are read",
      "🔔 Get notified of follow requests",
    ],
  },
  {
    emoji: "🛡️",
    title: "Privacy First",
    desc: "Your account, your rules. Set it up exactly how you want:",
    points: [
      "📖 Public — anyone can follow & chat with you",
      "🔐 Private — approve each follower manually",
      "🚫 Block anyone instantly at any time",
      "👁️ Hide your online status from others",
    ],
  },
  {
    emoji: "💬",
    title: "How Messaging Works",
    desc: "Smart messaging rules keep your inbox clean:",
    points: [
      "📨 Anyone can send you 1 message first",
      "✅ Follow each other for unlimited chat",
      "🔵 Blue ticks = seen (you can turn this off)",
      "⌨️ See when someone is typing in real time",
    ],
  },
];

export default function Register() {
  const [step, setStep] = useState(0);
  const [form, setForm] = useState({ username: "", email: "", password: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); setError("");
    try {
      const res = await API.post("/auth/register", form);
      login(res.data.user, res.data.token);
      navigate("/");
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed");
    }
    setLoading(false);
  };

  if (step < 3) {
    const s = STEPS[step];
    return (
      <div className="auth-page">
        <div className="auth-card">
          <div className="onboard-step">
            <div className="onboard-dots">
              {STEPS.map((_, i) => (
                <span key={i} className={`dot ${i === step ? "active" : ""}`} />
              ))}
            </div>
            <div className="onboard-emoji" key={step}>{s.emoji}</div>
            <h2 className="onboard-title">{s.title}</h2>
            <p className="onboard-desc">{s.desc}</p>
            <ul className="onboard-points">
              {s.points.map((p, i) => <li key={i}>{p}</li>)}
            </ul>
            <div className="onboard-actions">
              {step > 0 && (
                <button className="onboard-back" onClick={() => setStep(step - 1)}>← Back</button>
              )}
              <button className="auth-btn" onClick={() => setStep(step + 1)}>
                {step === STEPS.length - 1 ? "Create Account →" : "Next →"}
              </button>
            </div>
            <p className="auth-switch">
              Already have an account? <Link to="/login">Sign In</Link>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-logo">💬</div>
        <h1 className="auth-title">Create account</h1>
        <p className="auth-sub">Almost there! Fill in your details</p>
        {error && <div className="auth-error">{error}</div>}
        <form onSubmit={handleSubmit} className="auth-form">
          <div className="auth-field">
            <label>Username</label>
            <input type="text" placeholder="Pick a username"
              value={form.username}
              onChange={e => setForm({ ...form, username: e.target.value })} required />
          </div>
          <div className="auth-field">
            <label>Email</label>
            <input type="email" placeholder="your@email.com"
              value={form.email}
              onChange={e => setForm({ ...form, email: e.target.value })} required />
          </div>
          <div className="auth-field">
            <label>Password</label>
            <div className="pass-wrap">
              <input type={showPass ? "text" : "password"} placeholder="Min 6 characters"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                minLength={6} required />
              <button type="button" className="eye-btn" onClick={() => setShowPass(!showPass)}>
                {showPass ? "🙈" : "👁️"}
              </button>
            </div>
          </div>
          <button className="auth-btn" disabled={loading}>
            {loading ? "Creating..." : "Create Account 🎉"}
          </button>
        </form>
        <p className="auth-switch">
          Already have an account? <Link to="/login">Sign In</Link>
        </p>
      </div>
    </div>
  );
}
